const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401, error: 'Missing session token' } };
if (!body.policy_application_id) return { json: { _empty: true, status: 400, error: 'policy_application_id required' } };
return { json: {
  token: token,
  policy_application_id: body.policy_application_id,
  advisor_review_notes: body.advisor_review_notes || null
} };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && rows.id ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid or expired session' } };
const allowed = ['advisor','mga_principal','supervisor','admin'];
if (allowed.indexOf(row.user_role) < 0) return { json: { _unauthorized: true, status: 403, error: 'Role not permitted' } };
const i = $('Extract Inputs').item.json;
return { json: {
  _ok: true,
  user_id: row.id || row.user_id,
  user_role: row.user_role,
  policy_application_id: i.policy_application_id,
  advisor_review_notes: i.advisor_review_notes
} };

const ctx = $('Check Role').item.json;
const rows = $input.item.json;
const app = (Array.isArray(rows) ? rows[0] : rows) || null;
if (!app || !app.id) return { json: { _not_found: true } };
return { json: {
  application: app,
  user_id: ctx.user_id,
  user_role: ctx.user_role
} };

const app = $('Carry Application').item.json.application;
const resp = $input.item.json || {};
const decision = (resp && resp.ai_decision) || 'requires_human_review';
const needs_human = !!(resp && resp.needs_human);
let next_submission_status = app.submission_status;
let next_locked = app.locked;

if (decision === 'approved') {
  next_submission_status = 'submitted';   // Phase 6 hooks the actual carrier-API submit here.
  next_locked = true;                     // Stay locked through underwriting.
} else if (decision === 'rejected') {
  next_submission_status = 'draft';       // Bounce back to draft.
  next_locked = false;
} else {
  // requires_human_review or flagged — keep locked, status stays draft pending compliance officer.
  next_submission_status = app.submission_status;
  next_locked = true;
}

return { json: {
  application_id: app.id,
  client_id: app.client_id,
  advisor_id: app.advisor_id,
  ai_decision: decision,
  needs_human: needs_human,
  patch: {
    submission_status: next_submission_status,
    submitted_at: next_submission_status === 'submitted' ? new Date().toISOString() : app.submitted_at,
    locked: next_locked,
    updated_at: new Date().toISOString()
  }
} };
